<?php
namespace App\Domain\Combat\Factories;use App\Domain\Combat\CombatMitigationConfigProvider;use App\Domain\Combat\Data\CombatMitigationConfig;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Stats\DamageReductionCalculator;use App\Models\Monster;
final class MonsterCombatantFactory{private $provider;public function __construct(DamageReductionCalculator $legacy=null,CombatMitigationConfigProvider $provider=null){$this->provider=$provider;}public function make(Monster $m,$identifier=null){$identifier=$identifier===null?'monster:'.$m->id:$identifier;if(!is_string($identifier)||trim($identifier)==='')throw new \InvalidArgumentException('Monster identifier cannot be empty.');$config=$this->provider?$this->provider->current():CombatMitigationConfig::defaults();return new CombatantStats($identifier,$m->name,$m->max_health,$m->max_health,$m->attack,$m->defense,$m->accuracy_rate,$m->evasion_rate,$m->critical_chance,1.5,1.0,0,0,$config);}}
